import fs from 'fs';
import csv from 'csv-parser';
import { initializeApp } from 'firebase/app';
import { getFirestore, doc, setDoc } from 'firebase/firestore';

const firebaseConfig = {
    apiKey: "AIzaSyB8qJM5kA5t126rNWBPMCzEbzspTgHYGqQ",
    authDomain: "medipath-c91bf.firebaseapp.com",
    projectId: "medipath-c91bf",
    storageBucket: "medipath-c91bf.firebasestorage.app",
    messagingSenderId: "236982445915",
    appId: "1:236982445915:web:50e12a30e5e9994ae2dc7e"
};

const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

const CSV_PATH = "C:\\Users\\prana\\.cache\\kagglehub\\datasets\\kevinmathewsgeorge\\bangalore-doctors-dataset-from-practo\\versions\\1\\bangalore_doctors_final.csv";

const doctors = [];
let count = 0;

console.log('Reading CSV from:', CSV_PATH);

fs.createReadStream(CSV_PATH)
    .pipe(csv())
    .on('data', (data) => {
        // We limit seeding to the first 50 doctors for development purposes
        if (doctors.length < 50) {
            doctors.push({
                id: 'D-' + data.entry_id,
                name: data.name,
                specialty: data.specialty || 'General',
                degree: data.degree || 'MBBS',
                experience: data.experience_years ? parseInt(data.experience_years) : 0,
                fee: data.consultation_fee ? parseInt(data.consultation_fee) : 500,
                rating: data.rating ? parseFloat(data.rating) : 4.5,
                location: data.bangalore_location || 'Bangalore',
                latitude: data.latitude ? parseFloat(data.latitude) : 0,
                longitude: data.longitude ? parseFloat(data.longitude) : 0
            });
        }
    })
    .on('end', async () => {
        console.log(`Finished reading. Selected ${doctors.length} doctors. Seeding to Firestore...`);

        for (const docData of doctors) {
            try {
                const docRef = doc(db, 'doctors', docData.id);
                await setDoc(docRef, docData);
                count++;
                if (count % 10 === 0) console.log(`Seeded ${count} doctors...`);
            } catch (err) {
                console.error('Error seeding doctor:', docData.name, err);
            }
        }

        console.log(`Successfully seeded ${count} doctors into Firestore!`);
        process.exit(0);
    });

import { useState } from 'react';
import { useNavigate } from 'react-router-dom';
import { Stethoscope, User, ShieldCheck, ArrowRight, Loader2 } from 'lucide-react';
import { auth, db, googleProvider } from '../lib/firebase';
import { signInWithEmailAndPassword, createUserWithEmailAndPassword, updateProfile, signInWithPopup } from 'firebase/auth';
import { doc, setDoc, getDoc } from 'firebase/firestore';

export default function LoginPage() {
  const [isLogin, setIsLogin] = useState(true);
  const [role, setRole] = useState('patient');

  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [name, setName] = useState('');

  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const handleSubmit = async () => {
    if (!email.trim() || !password.trim() || (!isLogin && !name.trim())) {
      setError('Please fill in all fields.');
      return;
    }
    setError('');
    setLoading(true);

    try {
      // Save role to localStorage so App.jsx doesn't suffer a db race condition on route change
      localStorage.setItem('medai_role', role);
      if (isLogin) {
        const userCred = await signInWithEmailAndPassword(auth, email, password);
        // Ensure role in DB matches selected prototype role
        await setDoc(doc(db, 'users', userCred.user.uid), { role: role }, { merge: true });
        // Routing handled by App.jsx onAuthStateChanged listener
      } else {
        const userCred = await createUserWithEmailAndPassword(auth, email, password);
        const user = userCred.user;

        // Update display name
        await updateProfile(user, { displayName: name });

        // Create user profile in Firestore
        await setDoc(doc(db, 'users', user.uid), {
          email: user.email,
          name: name,
          role: role,
          createdAt: new Date().toISOString()
        });
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  const handleGoogleSignIn = async () => {
    setError('');
    setLoading(true);
    try {
      localStorage.setItem('medai_role', role);
      const result = await signInWithPopup(auth, googleProvider);
      const user = result.user;

      // Check if user document already exists
      const docRef = doc(db, 'users', user.uid);
      const docSnap = await getDoc(docRef);

      // If doc doesn't exist, this is a first-time Google sign up.
      // We will assign them the currently selected role.
      if (!docSnap.exists()) {
        await setDoc(docRef, {
          email: user.email,
          name: user.displayName,
          role: role,
          createdAt: new Date().toISOString(),
          authProvider: 'google'
        });
      } else {
        // Update existing user with selected role
        await setDoc(docRef, { role: role }, { merge: true });
      }
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  return (
    <div className="login-wrapper">
      {/* Left: Branding sidebar */}
      <div className="login-sidebar">
        <div className="pattern-overlay"></div>
        <div style={{ position: 'relative', zIndex: 1 }}>
          <div className="flex items-center gap-3 mb-8">
            <div className="w-12 h-12 rounded-xl flex items-center justify-center"
              style={{ background: 'rgba(255,255,255,0.2)', backdropFilter: 'blur(8px)' }}>
              <Stethoscope size={24} color="white" />
            </div>
            <div>
              <h1 className="text-3xl font-black text-white" style={{ letterSpacing: '-0.03em' }}>MedAI</h1>
              <div className="text-xs text-white/60 font-semibold tracking-widest uppercase">Clinical Decision Support</div>
            </div>
          </div>

          <h2 className="text-2xl font-bold text-white mb-4" style={{ lineHeight: 1.3 }}>
            Intelligent healthcare<br />for South Asian hospitals
          </h2>
          <p className="text-white/70 text-sm mb-8" style={{ lineHeight: 1.7, maxWidth: 380 }}>
            AI-powered symptom analysis, real-time doctor matching, medication management,
            and recovery tracking — all in one secure platform.
          </p>

          <div className="flex flex-col gap-3">
            {[
              { icon: '🔬', label: 'Bayesian doctor matching based on symptoms' },
              { icon: '💊', label: 'Medication schedule with reminders' },
              { icon: '📊', label: 'Recovery tracking & rehab videos' },
              { icon: '🛡️', label: 'Emergency SOS with instant alerts' },
            ].map((f, i) => (
              <div key={i} className="flex items-center gap-3 text-white/80 text-sm">
                <span className="text-lg">{f.icon}</span>
                <span>{f.label}</span>
              </div>
            ))}
          </div>
        </div>
        <div style={{
          position: 'absolute',
          bottom: '24px',
          left: '32px',
          fontSize: '10px',
          color: 'rgba(255, 255, 255, 0.4)',
          letterSpacing: '0.05em',
          fontWeight: 500,
          zIndex: 1
        }}>
          developed by pranay
        </div>
      </div>

      {/* Right: Login form */}
      <div className="login-form-section">
        <div style={{ width: '100%', maxWidth: 420 }} className="fade-in">
          <div className="mb-8">
            <h2 className="text-2xl font-bold mb-1">{isLogin ? 'Sign in to MedAI' : 'Create an Account'}</h2>
            <p className="text-sm" style={{ color: 'var(--text-secondary)' }}>
              {isLogin ? 'Access your healthcare portal' : 'Join the MedAI healthcare network'}
            </p>
          </div>

          {/* Role Toggle */}
          <div className="flex gap-2 mb-6 p-1 rounded-xl"
            style={{ background: 'var(--bg-section)', border: '1px solid var(--border)' }}>
            {[
              { val: 'patient', icon: <User size={16} />, label: 'Patient' },
              { val: 'doctor', icon: <Stethoscope size={16} />, label: 'Doctor' },
              { val: 'admin', icon: <ShieldCheck size={16} />, label: 'Admin' },
            ].map(r => (
              <button key={r.val} className="btn flex-1"
                onClick={() => setRole(r.val)}
                style={{
                  padding: '12px',
                  background: role === r.val ? (
                    r.val === 'admin' ? '#8b5cf6' : 
                    r.val === 'doctor' ? 'var(--primary)' : 'var(--success)'
                  ) : 'transparent',
                  color: role === r.val ? 'white' : 'var(--text-muted)',
                  borderRadius: '10px',
                  fontWeight: 600,
                  transition: 'all 0.25s',
                  boxShadow: role === r.val ? 'var(--shadow-sm)' : 'none',
                }}>
                <div className="flex items-center justify-center gap-1.5" style={{ whiteSpace: 'nowrap' }}>
                  {r.icon}
                  {r.label}
                </div>
              </button>
            ))}
          </div>

          {/* Form */}
          <div className="flex flex-col gap-4 mb-6">
            {!isLogin && (
              <div>
                <label className="block text-xs font-semibold mb-2 uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>
                  Full Name
                </label>
                <input
                  value={name}
                  onChange={e => setName(e.target.value)}
                  placeholder="Your full name"
                  onKeyDown={e => e.key === 'Enter' && handleSubmit()}
                />
              </div>
            )}
            <div>
              <label className="block text-xs font-semibold mb-2 uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>
                Email Address
              </label>
              <input
                type="email"
                value={email}
                onChange={e => setEmail(e.target.value)}
                placeholder="name@example.com"
                onKeyDown={e => e.key === 'Enter' && handleSubmit()}
              />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-2 uppercase tracking-wider" style={{ color: 'var(--text-muted)' }}>
                Password
              </label>
              <input
                type="password"
                value={password}
                onChange={e => setPassword(e.target.value)}
                placeholder="••••••••"
                onKeyDown={e => e.key === 'Enter' && handleSubmit()}
              />
            </div>
          </div>

          {error && (
            <div className="flex items-center gap-2 text-sm mb-4 p-3 rounded-lg"
              style={{ color: 'var(--danger)', background: 'var(--danger-light)' }}>
              ⚠️ {error}
            </div>
          )}

          <button
            className="btn btn-lg btn-full"
            onClick={handleSubmit}
            disabled={loading}
            style={{
              background: loading ? 'var(--border)' : (
                role === 'admin' ? '#8b5cf6' :
                role === 'doctor' ? 'var(--primary)' : 'var(--success)'
              ),
              color: 'white',
              fontWeight: 700,
              fontSize: '0.9375rem',
              marginBottom: '1rem'
            }}>
            {loading ? (
              <><span className="spinner"></span> {isLogin ? 'Authenticating...' : 'Creating account...'}</>
            ) : (
              <>{isLogin ? 'Sign In' : 'Sign Up'} <ArrowRight size={18} /></>
            )}
          </button>

          <div className="relative my-6">
            <div className="absolute inset-0 flex items-center">
              <div className="w-full border-t border-[var(--border)]"></div>
            </div>
            <div className="relative flex justify-center text-xs">
              <span className="bg-[var(--bg-main)] px-2 text-[var(--text-muted)]">Or continue with</span>
            </div>
          </div>

          <button
            className="btn btn-lg btn-full flex items-center justify-center gap-2 mb-4"
            onClick={handleGoogleSignIn}
            disabled={loading}
            style={{
              background: 'white',
              color: '#333',
              border: '1px solid #ddd',
              fontWeight: 600,
              fontSize: '0.9375rem',
            }}>
            <svg viewBox="0 0 24 24" width="18" height="18" xmlns="http://www.w3.org/2000/svg">
              <g transform="matrix(1, 0, 0, 1, 27.009001, -39.238998)">
                <path fill="#4285F4" d="M -3.264 51.509 C -3.264 50.719 -3.334 49.969 -3.454 49.239 L -14.754 49.239 L -14.754 53.749 L -8.284 53.749 C -8.574 55.229 -9.424 56.479 -10.684 57.329 L -10.684 60.329 L -6.824 60.329 C -4.564 58.239 -3.264 55.159 -3.264 51.509 Z" />
                <path fill="#34A853" d="M -14.754 63.239 C -11.514 63.239 -8.804 62.159 -6.824 60.329 L -10.684 57.329 C -11.764 58.049 -13.134 58.489 -14.754 58.489 C -17.884 58.489 -20.534 56.379 -21.484 53.529 L -25.464 53.529 L -25.464 56.619 C -23.494 60.539 -19.444 63.239 -14.754 63.239 Z" />
                <path fill="#FBBC05" d="M -21.484 53.529 C -21.734 52.809 -21.864 52.039 -21.864 51.239 C -21.864 50.439 -21.724 49.669 -21.484 48.949 L -21.484 45.859 L -25.464 45.859 C -26.284 47.479 -26.754 49.299 -26.754 51.239 C -26.754 53.179 -26.284 54.999 -25.464 56.619 L -21.484 53.529 Z" />
                <path fill="#EA4335" d="M -14.754 43.989 C -12.984 43.989 -11.404 44.599 -10.154 45.789 L -6.734 42.369 C -8.804 40.429 -11.514 39.239 -14.754 39.239 C -19.444 39.239 -23.494 41.939 -25.464 45.859 L -21.484 48.949 C -20.534 46.099 -17.884 43.989 -14.754 43.989 Z" />
              </g>
            </svg>
            Continue with Google
          </button>

          <div className="text-center text-sm" style={{ color: 'var(--text-secondary)' }}>
            {isLogin ? "Don't have an account? " : "Already have an account? "}
            <button
              onClick={() => { setIsLogin(!isLogin); setError(''); }}
              style={{ color: role === 'doctor' ? 'var(--primary)' : 'var(--success)', fontWeight: 600 }}>
              {isLogin ? 'Sign Up' : 'Sign In'}
            </button>
          </div>

          <div className="text-center mt-6 flex items-center justify-center gap-2 text-xs"
            style={{ color: 'var(--text-muted)' }}>
            <ShieldCheck size={14} />
            Secure Authentication powered by Firebase
          </div>
        </div>
      </div>
    </div >
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { ClipboardList, Plus, Trash2, ArrowRight, Save, UserSearch } from 'lucide-react';
import Navbar from '../../components/Navbar';
import SOSButton from '../../components/SOSButton';
import SOSModal from '../../components/SOSModal';
import { db } from '../../lib/firebase';
import { collection, addDoc, doc, updateDoc } from 'firebase/firestore';

export default function Prescriptions({ user, onLogout }) {
  const [saved, setSaved] = useState(false);
  const [showSOS, setShowSOS] = useState(false);
  const [sosAlert, setSosAlert] = useState(false);
  const navigate = useNavigate();

  const [localMeds, setLocalMeds] = useState([{ name: '', dosage: '', days: '', instruction: 'After meals' }]);
  const [localPatientInfo, setLocalPatientInfo] = useState({ email: '', name: '', diagnosis: '', symptoms: '' });

  const addMed = () => setLocalMeds(prev => [...prev, { name: '', dosage: '', days: '', instruction: 'After meals' }]);
  const updateMed = (i, field, val) => {
    const newMeds = [...localMeds];
    newMeds[i] = { ...newMeds[i], [field]: val };
    setLocalMeds(newMeds);
  };
  const removeMed = (i) => setLocalMeds(prev => prev.filter((_, mi) => mi !== i));

  const handleSave = async () => {
    // Validate
    const validMeds = localMeds.filter(m => m.name.trim());
    if (!localPatientInfo.email.trim() || validMeds.length === 0) {
      alert('Please enter patient email and at least one medication.');
      return;
    }

    setSaved(true);

    try {
      // Create a prescription document in Firestore
      const prescriptionData = {
        doctorId: user.uid,
        doctorName: user.name || user.email,
        patientEmail: localPatientInfo.email.trim().toLowerCase(),
        patientName: localPatientInfo.name.trim(),
        diagnosis: localPatientInfo.diagnosis.trim(),
        symptoms: localPatientInfo.symptoms.trim(),
        medications: validMeds.map(m => ({
          name: m.name,
          dosage: m.dosage,
          days: parseInt(m.days) || 1,
          instruction: m.instruction,
          times: [],      // Will be set in Timings page
          taken: []       // Will be populated when times are set
        })),
        createdAt: new Date().toISOString(),
        status: 'active'
      };

      const docRef = await addDoc(collection(db, 'prescriptions'), prescriptionData);

      // Navigate to timings page with the prescription ID
      setTimeout(() => {
        setSaved(false);
        navigate('/doctor/timings', { state: { prescriptionId: docRef.id, meds: validMeds } });
      }, 800);
    } catch (err) {
      console.error('Error saving prescription:', err);
      alert('Failed to save prescription. Please try again.');
      setSaved(false);
    }
  };

  return (
    <div style={{ minHeight: '100vh', background: 'var(--bg)' }}>
      {/* SOS Alert */}
      {sosAlert && (
        <div className="fade-in" style={{
          position: 'fixed', top: 16, right: 16, zIndex: 1500, maxWidth: 340,
          background: 'var(--bg-white)', border: '2px solid var(--danger)', borderRadius: 'var(--radius-lg)',
          padding: '16px', boxShadow: 'var(--shadow-lg)',
        }}>
          <div className="flex items-start justify-between mb-2">
            <div className="font-bold text-sm" style={{ color: 'var(--danger)' }}>🚨 SOS Alert Received</div>
            <button className="btn" onClick={() => setSosAlert(false)}
              style={{ background: 'transparent', color: 'var(--text-muted)', fontSize: 14, padding: '0 4px' }}>✕</button>
          </div>
          <p className="text-sm mb-3" style={{ color: 'var(--text-secondary)', lineHeight: 1.6 }}>
            A patient has sent an emergency alert.
          </p>
          <div className="flex gap-2">
            <button className="btn btn-danger btn-sm flex-1" onClick={() => setSosAlert(false)}>Respond</button>
            <button className="btn btn-ghost btn-sm" onClick={() => setSosAlert(false)}>Dismiss</button>
          </div>
        </div>
      )}

      <Navbar user={user} currentStep={1} onLogout={onLogout} />

      <div style={{ maxWidth: 860, margin: '0 auto', padding: '28px 20px' }}>
        <div className="section-header fade-in">
          <h1>Write Prescription</h1>
          <p>Enter patient details and prescribed medications</p>
        </div>

        {/* Patient Info */}
        <div className="med-card mb-5 fade-in" style={{ borderLeft: '4px solid var(--primary)' }}>
          <div className="flex items-center gap-2 mb-4">
            <UserSearch size={18} color="var(--primary)" />
            <h3 className="font-bold">Patient Information</h3>
          </div>
          <div className="grid gap-4" style={{ gridTemplateColumns: '1fr 1fr' }}>
            <div>
              <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>Patient Email</label>
              <input value={localPatientInfo.email} onChange={e => setLocalPatientInfo(p => ({ ...p, email: e.target.value }))} placeholder="patient@example.com" />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>Patient Name</label>
              <input value={localPatientInfo.name} onChange={e => setLocalPatientInfo(p => ({ ...p, name: e.target.value }))} placeholder="Full name" />
            </div>
          </div>
          <div className="grid gap-4 mt-3" style={{ gridTemplateColumns: '1fr 1fr' }}>
            <div>
              <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>Diagnosis</label>
              <input value={localPatientInfo.diagnosis} onChange={e => setLocalPatientInfo(p => ({ ...p, diagnosis: e.target.value }))} placeholder="Primary diagnosis / condition" />
            </div>
            <div>
              <label className="block text-xs font-semibold mb-1" style={{ color: 'var(--text-muted)' }}>Symptoms</label>
              <input value={localPatientInfo.symptoms} onChange={e => setLocalPatientInfo(p => ({ ...p, symptoms: e.target.value }))} placeholder="e.g. Fever, Cough, Fatigue..." />
            </div>
          </div>
        </div>

        {/* Medications */}
        <div className="med-card mb-5 fade-in">
          <div className="flex items-center justify-between mb-4">
            <div className="flex items-center gap-2">
              <ClipboardList size={18} color="var(--primary)" />
              <h3 className="font-bold">Medications</h3>
            </div>
            <button className="btn btn-outline btn-sm" onClick={addMed}>
              <Plus size={14} /> Add Medicine
            </button>
          </div>

          <div className="flex flex-col gap-3">
            {localMeds.map((med, i) => (
              <div key={i} className="p-4 rounded-lg" style={{ background: 'var(--bg-section)', border: '1px solid var(--border)' }}>
                <div className="flex items-center justify-between mb-3">
                  <span className="badge badge-primary">Medicine #{i + 1}</span>
                  {localMeds.length > 1 && (
                    <button className="btn btn-sm" onClick={() => removeMed(i)}
                      style={{ background: 'var(--danger-light)', color: 'var(--danger)', padding: '4px 10px' }}>
                      <Trash2 size={12} /> Remove
                    </button>
                  )}
                </div>
                <div className="grid gap-3" style={{ gridTemplateColumns: '2fr 1fr 1fr 1fr' }}>
                  <div>
                    <label className="block text-xs mb-1" style={{ color: 'var(--text-muted)' }}>Medicine Name</label>
                    <input value={med.name} onChange={e => updateMed(i, 'name', e.target.value)} placeholder="e.g. Paracetamol 500mg" />
                  </div>
                  <div>
                    <label className="block text-xs mb-1" style={{ color: 'var(--text-muted)' }}>Dosage</label>
                    <input value={med.dosage} onChange={e => updateMed(i, 'dosage', e.target.value)} placeholder="e.g. 1 tab" />
                  </div>
                  <div>
                    <label className="block text-xs mb-1" style={{ color: 'var(--text-muted)' }}>Days</label>
                    <input value={med.days} onChange={e => updateMed(i, 'days', e.target.value)} placeholder="e.g. 7" type="number" />
                  </div>
                  <div>
                    <label className="block text-xs mb-1" style={{ color: 'var(--text-muted)' }}>Instruction</label>
                    <select value={med.instruction} onChange={e => updateMed(i, 'instruction', e.target.value)}>
                      <option>After meals</option>
                      <option>Before meals</option>
                      <option>With food</option>
                      <option>Empty stomach</option>
                      <option>At bedtime</option>
                    </select>
                  </div>
                </div>
              </div>
            ))}
          </div>
        </div>

        <button className="btn btn-primary btn-lg btn-full" onClick={handleSave} disabled={saved}>
          {saved ? (<><Save size={18} /> Saved! Moving to Timings...</>) : (<>Save & Set Timings <ArrowRight size={18} /></>)}
        </button>
      </div>

      <SOSButton onPress={() => setShowSOS(true)} />
      {showSOS && <SOSModal onClose={() => setShowSOS(false)} doctorName="Emergency Services" />}
    </div>
  );
}

import { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { Search, Star, MapPin, Award, Users, ChevronRight, Plus, X } from 'lucide-react';
import Navbar from '../../components/Navbar';
import SOSButton from '../../components/SOSButton';
import SOSModal from '../../components/SOSModal';
import { SYMPTOM_DOCTOR_MAP, SYMPTOM_CATEGORIES } from '../../data/symptoms';
import { matchDoctors } from '../../utils/bayesian';
import { db } from '../../lib/firebase';
import { collection, addDoc, query, where, getDocs } from 'firebase/firestore';

export default function DoctorMatch({ user, onLogout, onSelectDoctor }) {
  const [selectedSymptoms, setSelectedSymptoms] = useState([]);
  const [matchedDoctors, setMatchedDoctors] = useState([]);
  const [searching, setSearching] = useState(false);
  const [customSymptom, setCustomSymptom] = useState('');
  const [showSOS, setShowSOS] = useState(false);
