                  fontWeight: 500,
                  borderRadius: '8px',
                }}>
                {cat}
              </button>
            ))}
          </div>

          {/* Symptom Pills */}
          <div className="flex flex-wrap gap-3 mb-5">
            {(SYMPTOM_CATEGORIES[activeCategory] || []).map(s => {
              const active = selectedSymptoms.includes(s);
              return (
                <button key={s} className="btn"
