          </div>

          {/* Selected Summary */}
          {selectedSymptoms.length > 0 && (
            <div className="p-4 rounded-xl" style={{ background: 'rgba(0,102,204,0.08)', border: '2px solid rgba(0,102,204,0.15)' }}>
